function plot_state_trajectories(obj, target_state_trajectory, approximated_state_trajectory, sampling_points)
    % PLOT_STATE_TRAJECTORIES Plot the target and approximated state trajectories.
    %
    %   Inputs:
    %       - TARGET_STATE_TRAJECTORY: an array of states, each state a struct, including the fields V_c, ..., I_z_R.
    %       - APPROXIMATED_STATE_TRAJECTORY: an array of states, each state a struct, including the fields V_c, ..., I_z_R.
    %       - SAMPLING_POINTS: an array of structs, generated by the function sample_state_trajectory_uniformly or
    %          sample_state_trajectory_by_waveform.

    hold on

    end_time = obj.get_state_trajectory_end_time(target_state_trajectory);
    times = 1e6 * linspace(0, end_time, length(target_state_trajectory));
    plot(times, [target_state_trajectory.I_coil], 'LineWidth', 2)

    end_time = obj.get_state_trajectory_end_time(approximated_state_trajectory);
    times = 1e6 * linspace(0, end_time, length(approximated_state_trajectory));
    plot(times, [approximated_state_trajectory.I_coil], 'LineWidth', 2)

    % Mark sampling points on the plot, use small red circles, use y-coordinate from target state trajectory
    for i = 1:length(sampling_points)
        plot(1e6 * sampling_points(i).time, target_state_trajectory(sampling_points(i).index).I_coil, 'ro', 'MarkerSize', 3)
    end

    set(gcf, 'color', 'w')
    xlabel('Time (µs)');
    ylabel('Coil current (A)');

    hold off
end
